'use client';

import { useEffect, useMemo } from 'react';
import { StepFormHeader } from './StepFormHeader';
import { usePlaywrightStepSequencer } from '../../context/PlaywrightStepSequencerContext';
import { useStepFormState } from './useStepFormState';
import { buildEmpty } from './step-form-utils';
import {
  Button,
  Checkbox,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  Input,
  Label,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  Separator,
  Textarea,
} from '@/shared/ui/primitives.public';
import { useSaveSelectorRegistryEntryMutation } from '@/features/integrations/hooks/useSelectorRegistry';
import {
  SELECTOR_REGISTRY_DEFAULT_PROFILES,
} from '@/shared/lib/browser-execution/selector-registry-metadata';
import {
  formatSelectorRegistryRoleLabel,
  getCompatibleSelectorRolesForStepField,
  isSelectorRegistryEntryCompatibleWithStepField,
} from '@/shared/lib/browser-execution/selector-registry-roles';

export function StepFormModal(): React.JSX.Element | null {
  const {
    editingStep,
    handleCreateStep,
    handleUpdateStep,
    isSaving,
    websites,
    flows,
  } = usePlaywrightStepSequencer();

  const {
    draft, setDraft,
    isOpen, isEditing,
    registryQuery,
    registrySelectorEntries,
    registryNamespacesForSelect,
    selectedRegistryNamespace,
    selectorBindingMode,
    selectorFallback,
    registrySaveMessage, setRegistrySaveMessage,
    registrySaveError, setRegistrySaveError,
  } = useStepFormState();

  // Sync draft when editing step changes
  useEffect(() => {
    if (editingStep) {
      setDraft(editingStep);
    } else {
      setDraft(buildEmpty());
    }
    setRegistrySaveMessage(null);
    setRegistrySaveError(null);
  }, [editingStep, setDraft, setRegistrySaveMessage, setRegistrySaveError]);

  const selectedRegistryProfile = (draft.inputBindings?.['selector']?.selectorProfile ?? draft.selectorProfile ?? 
    SELECTOR_REGISTRY_DEFAULT_PROFILES[selectedRegistryNamespace as keyof typeof SELECTOR_REGISTRY_DEFAULT_PROFILES]);

  const registryProfiles = useMemo(
    () =>
      Array.from(
        new Set([selectedRegistryProfile, ...(registryQuery.data?.profiles ?? [])])
      ).sort(),
    [registryQuery.data?.profiles, selectedRegistryProfile]
  );

  const registryProfilesForSelect = useMemo(
    () =>
      registryProfiles.includes(selectedRegistryProfile)
        ? registryProfiles
        : [selectedRegistryProfile, ...registryProfiles],
    [registryProfiles, selectedRegistryProfile]
  );
  const selectedRegistryEntry = useMemo(
    () =>
      registrySelectorEntries.find(
        (entry) =>
          entry.key === draft.inputBindings?.['selector']?.selectorKey &&
          entry.profile === selectedRegistryProfile &&
          entry.namespace === selectedRegistryNamespace
      ) ??
      registrySelectorEntries.find(
        (entry) =>
          entry.key === draft.inputBindings?.['selector']?.selectorKey &&
          entry.namespace === selectedRegistryNamespace
      ) ??
      null,
    [registrySelectorEntries, selectedRegistryNamespace, selectedRegistryProfile, draft.inputBindings?.['selector']?.selectorKey]
  );
  const selectorExpectedRoles = useMemo(
    () => getCompatibleSelectorRolesForStepField(draft.type ?? 'click'),
    [draft.type]
  );
  const selectorExpectedRoleLabels = useMemo(
    () => selectorExpectedRoles.map((role) => formatSelectorRegistryRoleLabel(role) ?? role),
    [selectorExpectedRoles]
  );

  const selectedRegistryEntryCompatible =
    selectedRegistryEntry === null
      ? true
      : isSelectorRegistryEntryCompatibleWithStepField(selectedRegistryEntry, draft.type ?? 'click');
  const registryEntriesForProfile = useMemo(
    () =>
      registrySelectorEntries.filter(
        (entry) =>
          entry.namespace === selectedRegistryNamespace &&
          entry.profile === selectedRegistryProfile &&
          (isSelectorRegistryEntryCompatibleWithStepField(entry, draft.type ?? 'click') ||
            (entry.key === selectorBinding?.selectorKey &&
              entry.namespace === selectedRegistryNamespace &&
              entry.profile === selectedRegistryProfile))
      ),
    [
      draft.type,
      registrySelectorEntries,
      selectedRegistryNamespace,
      selectedRegistryProfile,
      selectorBinding?.selectorKey,
    ]
  );

  if (!isOpen) return null;

  const close = (): void => {
    setIsCreateStepOpen(false);
    setEditingStep(null);
  };

  const set = <K extends keyof StepDraft>(key: K, value: StepDraft[K]): void =>
    setDraft((prev) => ({ ...prev, [key]: value }));

  const setSelectorBinding = (updates: Partial<PlaywrightStepInputBinding>): void => {
    setDraft((prev) => {
      const existing = prev.inputBindings?.['selector'];
      const nextBinding: PlaywrightStepInputBinding = {
        mode: existing?.mode ?? 'literal',
        ...existing,
        ...updates,
      };
      return {
        ...prev,
        inputBindings: {
          ...(prev.inputBindings ?? {}),
          selector: nextBinding,
        },
      };
    });
  };

  const connectSelectorRegistryEntry = (entry: SelectorRegistryEntry): void => {
    const fallbackSelector = (entry.preview[0] ?? selectorFallback) || null;
    setDraft((prev) => ({
      ...prev,
      selector: fallbackSelector,
      selectorNamespace: entry.namespace,
      selectorKey: entry.key,
      selectorProfile: entry.profile,
      inputBindings: {
        ...(prev.inputBindings ?? {}),
        selector: {
          mode: 'selectorRegistry',
          selectorNamespace: entry.namespace,
          selectorKey: entry.key,
          selectorProfile: entry.profile,
          selectorRole: entry.role,
          fallbackSelector,
        },
      },
    }));
  };

  const handleSaveFallbackAsRegistryOverride = async (): Promise<void> => {
    if (!selectedRegistryEntry) return;
    const selector = selectorFallback.trim();
    if (!selector) return;
    const valueJson = buildRegistryOverrideValueJson(selectedRegistryEntry, selector);
    if (!valueJson) {
      setRegistrySaveMessage(null);
      setRegistrySaveError('This registry entry type cannot be updated from a single selector.');
      return;
    }

    setRegistrySaveMessage(null);
    setRegistrySaveError(null);
    try {
      const result = await saveRegistryMutation.mutateAsync({
        namespace: selectedRegistryNamespace,
        profile: selectedRegistryProfile,
        key: selectedRegistryEntry.key,
        valueJson,
      });
      setSelectorBinding({
        mode: 'selectorRegistry',
        selectorNamespace: result.namespace,
        selectorKey: result.key,
        selectorProfile: result.profile,
        selectorRole: selectedRegistryEntry.role,
        fallbackSelector: result.preview[0] ?? selector,
      });
      set('selector', result.preview[0] ?? selector);
      setRegistrySaveMessage(`Saved registry override for ${result.profile}/${result.key}.`);
    } catch (error) {
      setRegistrySaveError(error instanceof Error ? error.message : 'Failed to save registry override.');
    }
  };

  const handleSubmit = async (e: React.FormEvent): Promise<void> => {
    e.preventDefault();
    const name = draft.name?.trim();
    if (!name || !draft.type) return;
    const inputBindings: Record<string, PlaywrightStepInputBinding> = {
      ...(draft.inputBindings ?? {}),
    };
    const selector = draft.selector?.trim() || null;

    if (SELECTOR_TYPES.includes(draft.type)) {
      const selectorBinding = inputBindings['selector'];
      if (selectorBinding?.mode === 'selectorRegistry') {
        const selectorNamespace = inferSelectorRegistryNamespace({
          namespace: selectorBinding.selectorNamespace ?? draft.selectorNamespace ?? null,
          selectorKey: selectorBinding.selectorKey ?? draft.selectorKey ?? null,
          selectorProfile: selectorBinding.selectorProfile ?? draft.selectorProfile ?? null,
        });
        inputBindings['selector'] = {
          mode: 'selectorRegistry',
          selectorNamespace,
          selectorKey: selectorBinding.selectorKey?.trim() || null,
          selectorProfile: selectorBinding.selectorProfile?.trim() || null,
          selectorRole: selectorBinding.selectorRole ?? selectedRegistryEntry?.role ?? null,
          fallbackSelector: selectorBinding.fallbackSelector?.trim() || selector,
        };
      } else if (selectorBinding?.mode === 'disabled') {
        inputBindings['selector'] = {
          mode: 'disabled',
          disabledReason: selectorBinding.disabledReason?.trim() || 'Selector intentionally disabled',
          fallbackSelector: selectorBinding.fallbackSelector?.trim() || selector,
        };
      } else {
        inputBindings['selector'] = {
          mode: 'literal',
          value: selector,
        };
      }
    } else {
      delete inputBindings['selector'];
    }

    const payload = {
      name,
      description: draft.description?.trim() || null,
      type: draft.type,
      selector,
      value: draft.value?.trim() || null,
      url: draft.url?.trim() || null,
      key: draft.key?.trim() || null,
      timeout: draft.timeout ?? null,
      script: draft.script?.trim() || null,
      inputBindings,
      websiteId: draft.websiteId ?? null,
      flowId: draft.flowId ?? null,
      tags: draft.tags ?? [],
      sortOrder: draft.sortOrder ?? 0,
      aiSystemPrompt: draft.aiSystemPrompt?.trim() || null,
      aiInputSource: draft.aiInputSource ?? null,
      aiGoal: draft.aiGoal?.trim() || null,
      aiMaxIterations: draft.aiMaxIterations ?? null,
      aiLoopEvaluatorInputSource: draft.aiLoopEvaluatorInputSource ?? null,
    };

    if (isEditing && editingStep) {
      await handleUpdateStep(editingStep.id, payload);
    } else {
      await handleCreateStep(payload);
    }
  };

  const stepType = draft.type ?? 'click';
  const showSelector = SELECTOR_TYPES.includes(stepType)
    || (AI_EVALUATE_TYPES.includes(stepType) && draft.aiInputSource === 'selector_text')
    || (AI_INJECT_TYPES.includes(stepType) && draft.aiLoopEvaluatorInputSource === 'selector_text');
  const showValue = VALUE_TYPES.includes(stepType);
  const showUrl = URL_TYPES.includes(stepType);
  const showTimeout = TIMEOUT_TYPES.includes(stepType);
  const showScript = SCRIPT_TYPES.includes(stepType);
  const showAiEvaluate = AI_EVALUATE_TYPES.includes(stepType);
  const showAiInject = AI_INJECT_TYPES.includes(stepType);

  return (
    <Dialog open={isOpen} onOpenChange={(open) => { if (!open) close(); }}>
      <DialogContent className='max-w-lg'>
        <StepFormHeader isEditing={isEditing} />

        <form onSubmit={(e) => void handleSubmit(e)} className='space-y-4'>
          <StepFormInputs draft={draft} set={set} setSelectorBinding={setSelectorBinding} />

          {/* Description */}
          <div className='space-y-1.5'>
            <Label htmlFor='step-desc'>Description</Label>
            <Textarea
              id='step-desc'
              value={draft.description ?? ''}
              onChange={(e) => set('description', e.target.value || null)}
              placeholder='What does this step do?'
              rows={2}
            />
          </div>

          {/* Type-specific parameters */}
          {showSelector && (
            <StepFormSelectorRegistry
              draft={draft}
              set={set}
              setSelectorBinding={setSelectorBinding}
              selectorBindingMode={selectorBindingMode}
              selectedRegistryNamespace={selectedRegistryNamespace as string}
              selectedRegistryProfile={selectedRegistryProfile as string}
              registryNamespacesForSelect={registryNamespacesForSelect}
              registryProfilesForSelect={registryProfilesForSelect}
              registrySelectorEntries={registrySelectorEntries}
              registryEntriesForProfile={registryEntriesForProfile}
              connectSelectorRegistryEntry={connectSelectorRegistryEntry}
            />
          )}

          <Separator />

          {showTimeout ? (
            <div className='space-y-1.5'>
              <Label htmlFor='step-timeout'>Timeout (ms)</Label>
              <Input
                id='step-timeout'
                type='number'
                min={0}
                value={draft.timeout ?? ''}
                onChange={(e) =>
                  set('timeout', e.target.value ? Number(e.target.value) : null)
                }
                placeholder='e.g. 5000'
              />
            </div>
          ) : null}

          {showScript ? (
            <div className='space-y-1.5'>
              <Label htmlFor='step-script'>Script</Label>
              <Textarea
                id='step-script'
                value={draft.script ?? ''}
                onChange={(e) => set('script', e.target.value || null)}
                placeholder='// Custom Playwright script…'
                rows={5}
                className='font-mono text-xs'
              />
            </div>
          ) : null}

          {showAiEvaluate ? (
            <div className='space-y-3 rounded border border-fuchsia-500/20 bg-fuchsia-500/5 p-3'>
              <div className='space-y-1.5'>
                <Label>Input source</Label>
                <Select
                  value={draft.aiInputSource ?? 'screenshot'}
                  onValueChange={(v) => set('aiInputSource', v as PlaywrightAiEvaluateInputSource)}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {AI_EVALUATE_INPUT_SOURCES.map(([source, label]) => (
                      <SelectItem key={source} value={source}>{label}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <p className='text-xs text-muted-foreground'>
                  What the AI will receive: a screenshot image, raw HTML, body text, or the text of a specific element.
                </p>
              </div>

              <p className='text-xs text-muted-foreground'>
                The AI model is configured in{' '}
                <a href='/admin/brain?tab=routing' className='underline' target='_blank' rel='noreferrer'>
                  AI Brain → Playwright
                </a>
                .
              </p>

              <div className='space-y-1.5'>
                <Label htmlFor='step-ai-prompt'>System prompt</Label>
                <Textarea
                  id='step-ai-prompt'
                  value={draft.aiSystemPrompt ?? ''}
                  onChange={(e) => set('aiSystemPrompt', e.target.value || null)}
                  placeholder='Describe what you want the AI to evaluate. For example: "Determine whether the checkout button is visible and enabled. Respond with YES or NO followed by a brief explanation."'
                  rows={5}
                />
              </div>
            </div>
          ) : null}

          {showAiInject ? (
            <div className='space-y-3 rounded border border-violet-500/20 bg-violet-500/5 p-3'>
              <div className='space-y-1.5'>
                <Label htmlFor='step-ai-goal'>Goal</Label>
                <Textarea
                  id='step-ai-goal'
                  value={draft.aiGoal ?? ''}
                  onChange={(e) => set('aiGoal', e.target.value || null)}
                  placeholder='Describe the objective. For example: "Click the Accept cookies button if it is present, then navigate to the checkout page."'
                  rows={3}
                />
                <p className='text-xs text-muted-foreground'>
                  The AI will generate and execute Playwright code each iteration to pursue this goal.
                </p>
              </div>

              <div className='space-y-1.5'>
                <Label htmlFor='step-ai-max-iterations'>Max iterations</Label>
                <Input
                  id='step-ai-max-iterations'
                  type='number'
                  min={1}
                  max={10}
                  value={draft.aiMaxIterations ?? 3}
                  onChange={(e) => set('aiMaxIterations', Math.min(10, Math.max(1, Number(e.target.value) || 3)))}
                />
                <p className='text-xs text-muted-foreground'>
                  How many inject–execute cycles to attempt before giving up. 1–10.
                </p>
              </div>

              <div className='space-y-1.5'>
                <Label>Evaluator loop</Label>
                <Select
                  value={draft.aiLoopEvaluatorInputSource ?? ''}
                  onValueChange={(v) => set('aiLoopEvaluatorInputSource', v ? v as PlaywrightAiEvaluateInputSource : null)}
                >
                  <SelectTrigger>
                    <SelectValue placeholder='Disabled' />
                  </SelectTrigger>
                  <SelectContent>
                    {AI_INJECT_LOOP_EVALUATOR_OPTIONS.map(([source, label]) => (
                      <SelectItem key={source} value={source}>{label}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <p className='text-xs text-muted-foreground'>
                  When enabled, the AI Evaluator re-assesses page state between injections, feeding its output back to the injector for the next iteration.
                </p>
              </div>

              <p className='text-xs text-muted-foreground'>
                The AI model is configured in{' '}
                <a href='/admin/brain?tab=routing' className='underline' target='_blank' rel='noreferrer'>
                  AI Brain → Playwright
                </a>{' '}
                (capability: <code className='rounded bg-muted px-0.5 font-mono'>playwright.ai_code_injector</code>).
              </p>

              <div className='space-y-1.5'>
                <Label htmlFor='step-ai-inject-prompt'>System prompt override</Label>
                <Textarea
                  id='step-ai-inject-prompt'
                  value={draft.aiSystemPrompt ?? ''}
                  onChange={(e) => set('aiSystemPrompt', e.target.value || null)}
                  placeholder='Optional: override the default injector system prompt.'
                  rows={3}
                />
              </div>
            </div>
          ) : null}

          <Separator />

          {/* Scope */}
          <div className='space-y-2'>
            <Label>Scope</Label>
            <div className='flex items-center gap-2'>
              <Checkbox
                id='step-shared'
                checked={draft.websiteId === null}
                onCheckedChange={(checked) => {
                  if (checked) {
                    set('websiteId', null);
                    set('flowId', null);
                  } else {
                    set('websiteId', websites[0]?.id ?? null);
                    set('flowId', null);
                  }
                }}
              />
              <label htmlFor='step-shared' className='cursor-pointer text-sm'>
                Shared (available to all websites)
              </label>
            </div>

            {draft.websiteId !== null ? (
              <div className='ml-6 space-y-2'>
                {/* Website select */}
                <div className='space-y-1'>
                  <Label className='text-xs text-muted-foreground'>Website</Label>
                  <Select
                    value={draft.websiteId ?? ''}
                    onValueChange={(v) => {
                      set('websiteId', v || null);
                      set('flowId', null);
                    }}
                  >
                    <SelectTrigger className='h-8 text-xs'>
                      <SelectValue placeholder='Select website…' />
                    </SelectTrigger>
                    <SelectContent>
                      {websites.map((w) => (
                        <SelectItem key={w.id} value={w.id}>{w.name}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                {/* Flow select (optional) */}
                {draft.websiteId ? (
                  <div className='space-y-1'>
                    <Label className='text-xs text-muted-foreground'>Flow (optional)</Label>
                    <Select
                      value={draft.flowId ?? '__none__'}
                      onValueChange={(v) => set('flowId', v === '__none__' ? null : v)}
                    >
                      <SelectTrigger className='h-8 text-xs'>
                        <SelectValue placeholder='Any flow' />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value='__none__'>Any flow</SelectItem>
                        {flows
                          .filter((f) => f.websiteId === draft.websiteId)
                          .map((f) => (
                            <SelectItem key={f.id} value={f.id}>{f.name}</SelectItem>
                          ))}
                      </SelectContent>
                    </Select>
                  </div>
                ) : null}
              </div>
            ) : null}
          </div>

          {/* Tags */}
          <TagsInput
            id='step-tags'
            label='Tags'
            value={draft.tags ?? []}
            onChange={(tags) => set('tags', tags)}
            placeholder='e.g. checkout, login…'
          />

          <DialogFooter>
            <Button type='button' variant='outline' onClick={close} disabled={isSaving}>
              Cancel
            </Button>
            <Button type='submit' disabled={isSaving || !draft.name?.trim()}>
              {isSaving ? 'Saving…' : isEditing ? 'Update Step' : 'Create Step'}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}
